// // This module compares two 8-bit inputs, a and b, and outputs a single bit. The output, out1, will be LOW (0) if input a is less than input b; otherwise, it will be HIGH (1).
module top_module(
    a,
    b,
    out1
);input [7:0]a, b;

output reg out1;

always@(a,b) begin
    if(a<b)
    out1=1'b1;
    else
    out1=1'b0;
end

endmodule
